import { ethers } from "ethers";

// Function to connect to the Ethereum network
async function connectToNetwork() {
  if (typeof window.ethereum !== 'undefined') {
    await window.ethereum.request({ method: 'eth_requestAccounts' });
    const provider = new ethers.providers.Web3Provider(window.ethereum);
    return provider;
  } else {
    console.log("Ethereum browser extension not detected");
    return null;
  }
}

// Function to send a transaction
async function sendTransaction(contract, methodName, args) {
  const provider = await connectToNetwork();
  if (provider) {
    const signer = provider.getSigner();
    const txResponse = await contract[methodName](...args, { gasLimit: 300000 });
    return txResponse.wait();
  } else {
    console.log("Failed to send transaction");
  }
}

